(function (window) {
  function JQueryLite(selector) {
    this.nodes = typeof selector === "string" ? Array.prototype.slice.call(document.querySelectorAll(selector)) : [selector || document];
  }
  JQueryLite.prototype.ready = function (fn) { document.addEventListener("DOMContentLoaded", fn); return this; };
  JQueryLite.prototype.on = function () { return this; };
  JQueryLite.prototype.click = function () { return this; };
  JQueryLite.prototype.dataTable = function () { return this; };
  JQueryLite.prototype.niceScroll = function () { return this; };
  JQueryLite.prototype.addClass = function () { return this; };
  JQueryLite.prototype.removeClass = function () { return this; };
  JQueryLite.prototype.toggleClass = function () { return this; };
  JQueryLite.prototype.slideToggle = function () { return this; };
  JQueryLite.prototype.dropdown = function () { return this; };
  function $(selector) { return new JQueryLite(selector); }
  $.fn = JQueryLite.prototype;
  window.$ = window.jQuery = $;
})(window);
